import * as React from 'react';
import { BarChart } from '@mui/x-charts/BarChart';
import { LineChart } from '@mui/x-charts/LineChart';
import { ChartContainer } from '@mui/x-charts/ChartContainer';

const experienceData = [1,2, 2, 2, 1, 3, 3, 3 ];
const proficiencyData = [1, 2, 2, 2, 3, 2, 3, 3 ];
const xLabels = [
  'SQL',
  'MongoDB',
  'Express.js',
  'Node.js',
  'React.js',
  'JavaScript',
  'CSS, HTML',
  'Bootstrap',
];

export function SimpleBarChart() {
  return (
    <BarChart 
      sx={{
        // animation
        "@keyframes width-increase3": {
                    "0%": {
                        // opacity: "0"
                        transform: "scale(0.3) rotate(0deg) translateX(-30%) translateY(30%)",
                        opacity: "0"
                      },
                      
                    "100%": {
                        // opacity: "100"
                        transform: "scale(1) rotate(0deg) translateX(0%) translateY(0%)",
                        opacity: "1"
                    }
                },
                animation:  "width-increase3 2s ease ",  
        
        '.MuiChartsAxis-tickLabel ': {
          
          fill : "white"
        },
        '.MuiChartsAxis-tick' : {
          fill :'white',
          stroke : 'white'
        },
        '.MuiChartsAxis-line ':{
          stroke: 'white'
        },
        '.MuiChartsLegend-series tspan':{
          fill : 'white',
        },
        
        }}

      width={700}
      height={270}
      series={[
        { data: proficiencyData, label: 'Proficiency (0 to 3)', id: 'proficiencyId' },
        { data: experienceData, label: 'Experience (years)', id: 'experienceId' },
      ]}
     
      xAxis={[{ data: xLabels, scaleType: 'band' }]}
    />
  );
}

